#!/bin/bash
awk '($7 > 1023 && $7 != "3389" && $7 != "5900" && $7 != "8080" && $7 != "8000" && $7 != "8443") && ($3 ~ /^10\./ || $3 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $3 ~ /^192\.168\./) && !($5 ~ /^10\./ || $5 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $5 ~ /^192\.168\./) {print $1, $3, $4, $5, $6, $7, $12}' conn.log | head -n 20